```holoscript
object Pistol @grabbable {
  geometry: 'model/pistol.glb'
  physics: { mass: 0.8 }

  stats: { damage: 15, fireRate: 300, projectileSpeed: 40, maxAmmo: 12 }
  ammo: 12
  lastFire: 0

  children: {
    transform muzzle { position: [0, 0.05, 0.15] }
  }

  onTrigger: {
    let now = Date.now()
    if (now - this.lastFire < this.stats.fireRate) return
    if (this.ammo <= 0) { audio.play('click_empty'); return }

    this.lastFire = now
    this.ammo--

    spawn(Bullet, {
      position: this.muzzle.worldPosition,
      velocity: this.muzzle.forward * this.stats.projectileSpeed,
      damage: this.stats.damage,
      owner: player.id
    })

    particles.spawn('muzzle_flash', this.muzzle.worldPosition)
    audio.play3d('pistol_fire', this.position)
    haptics.pulse('right', 0.4, 50)
  }
}

object Bullet {
  geometry: 'sphere'
  scale: 0.02
  material: { type: 'emissive', color: '#ffff00', emissiveIntensity: 2 }
  physics: { type: 'dynamic', mass: 0.01, continuous: true }
  lifetime: 2000

  onSpawn: { setTimeout(() => this.destroy(), this.lifetime) }

  onCollision(other): {
    if (other.id === this.owner) return
    if (other.health) other.takeDamage(this.damage)
    particles.spawn('bullet_impact', this.position)
    this.destroy()
  }
}
