object TeleportPad @pointable {
  geometry: 'cylinder'
  position: [0, 0.05, 0]
  scale: [1.5, 0.1, 1.5]
  color: '#8b5cf6'

  destination: [20, 0, 20]

  children: {
    particles TeleportRing {
      emitter: 'ring'
      radius: 1.5
      emission: { rate: 30 }
      particle: {
        texture: 'sparkle'
        size: [0.05, 0.12]
        lifetime: [1, 2]
        color: ['#a855f7', '#c084fc', '#e879f9']
      }
      physics: { velocity: [0, 1.5, 0] }
    }

    light PadGlow {
      type: 'point'
      color: '#a855f7'
      intensity: 1
      range: 3
    }
  }

  animation pulse {
    property: 'children.PadGlow.intensity'
    from: 0.5
    to: 1.5
    duration: 1000
    loop: infinite
    easing: 'easeInOutSine'
  }

  onPoint: {
    // Departure effects
    particles.spawn('teleport_burst', player.position)
    audio.play3d('teleport_whoosh', player.position)
    player.visible = false

    setTimeout(() => {
      // Teleport
      player.position = this.destination
      player.visible = true

      // Arrival effects
      particles.spawn('teleport_arrive', this.destination)
      audio.play3d('teleport_arrive', this.destination)
    }, 500)
  }
}
