object LootCrate @grabbable @throwable @breakable {
  geometry: 'model/crate.glb'
  position: [0, 0.5, 0]

  physics: { mass: 3, restitution: 0.2 }

  breakable: {
    threshold: 4
    shatterPattern: 'wood'
    fragments: 8
  }

  lootTable: [
    { item: 'health_pack', chance: 0.4 },
    { item: 'ammo_box', chance: 0.3 },
    { item: 'shield_boost', chance: 0.2 },
    { item: 'power_core', chance: 0.1 }
  ]

  onBreak: {
    audio.play3d('crate_smash', this.position)
    particles.spawn('wood_splinters', this.position)

    // Roll for loot
    let roll = Math.random()
    let cumulative = 0

    for (let loot of this.lootTable) {
      cumulative += loot.chance
      if (roll <= cumulative) {
        spawn(loot.item, {
          position: this.position + [0, 0.5, 0],
          velocity: [Math.random() - 0.5, 3, Math.random() - 0.5]
        })
        break
      }
    }
  }
}
